def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        score = 0.0
        factor = 1.0
        adjust = 0.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 3:
            temp_sum = 0
            for a in range(1, 7):
                inner_sum = 0
                for b in range(1, a + 3):
                    inner_sum += (ratio ** b) / (b + a)
                temp_sum += ((-1) ** a) * inner_sum / (a + 1)
            factor = np.tanh(ratio - 3) + 1.5
            score = abs(temp_sum) * factor * 2.5
            if ratio > 5:
                score += np.log(ratio) * 10
            priorities[i] = score
        elif 2 < ratio <= 3:
            decay = 1.0
            for r in range(1, 6):
                decay *= max(0.1, 1 - (ratio / (r + ratio + 0.5))**2)
            sum_vals = 0
            for x in range(1, 10):
                sign = (-1)**(x+1)
                sum_vals += sign * (ratio ** x) / (x * 2 + 1)
            score = abs(sum_vals) * decay * 12
            if ratio > 2.5:
                extra = 0
                for y in range(1, 4):
                    extra += (ratio ** y) / (y + 1)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            base_score = 0
            for q in range(1, 15):
                if q % 2 == 0:
                    base_score += (ratio ** q) / (q + 3)
                else:
                    base_score -= (ratio ** q) / (q + 2)
            decay_factor = 1.0
            for r in range(1, 5):
                decay_factor *= (1 - 1 / (r + ratio + 1))
            priorities[i] = abs(base_score) * decay_factor * 8
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 20):
                if p % 4 == 0:
                    temp_score += (ratio ** p) / (p + 1)
                else:
                    temp_score -= (ratio ** p) / (p * 2)
            multiplier = 25 if ratio < 0.2 else 18 if ratio < 0.4 else 12 if ratio < 0.6 else 7 if ratio < 0.8 else 3
            score = abs(temp_score) * multiplier
            if ratio > 0.85:
                extra = 0
                for m in range(1, 8):
                    extra += (ratio ** m) / (m * 3 + 1)
                score += extra * 2
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    return priorities
